import{_ as o,o as t,c as s,ae as a}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Roku Testing","description":"","frontmatter":{"title":"Roku Testing","slug":"sdk-roku-testing"},"headers":[],"relativePath":"developer-hub/sdk-roku-testing.md","filePath":"developer-hub/sdk-roku-testing.md"}'),i={name:"developer-hub/sdk-roku-testing.md"};function r(n,e,l,c,d,u){return t(),s("div",null,[...e[0]||(e[0]=[a('<h3 id="sample-test-app" tabindex="-1">Sample Test App <a class="header-anchor" href="#sample-test-app" aria-label="Permalink to &quot;Sample Test App&quot;">​</a></h3><ol><li>To test the Branch test Roku app, open <code>./input/source/libs/Main.brs</code> and modify the following line:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>options.branchKey = &quot;key_live_TODO_YOUR_BRANCH_KEY_HERE&quot;</span></span></code></pre></div><ol start="2"><li>Replace <code>key_live_TODO_YOUR_BRANCH_KEY_HERE</code> with your Branch Key from the <a href="https://branch.dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Branch Dashboard</a>.</li></ol><div class="info custom-block"><p class="custom-block-title">Live vs Test Mode</p><p>You can also use your Testing Mode &quot;Test Key&quot; which can be found by changing the toggling in the top left corner of your Branch dashboard from &quot;Live&quot; to &quot;Test&quot;<br> The resulting key would look similar to this: key_test_TODO_YOUR_BRANCH_KEY_HERE</p><p>Why use Test?<br> If you are planning to test a bunch of Event Names that won&#39;t be in the Live dashboard reports then using Test Mode will keep names from being added to the event pick list in Live mode.</p></div><ol start="3"><li>Select all folders (<code>components</code>, <code>images</code>, <code>manifest</code>, <code>source</code>) except the <code>out</code> folder. Compress these four files into a zip file. Move this zip file to the <code>out</code> folder for convenience.</li><li>Connect to your Roku and upload the zip file. If you have not previously done this, be sure to check out <a href="https://blog.roku.com/developer/developer-setup-guide" target="_blank" rel="noreferrer">Roku&#39;s guide</a> to configuring your device, uploading builds from your computer, and so on. Please email <a href="mailto:ottctv@branch.com" target="_blank" rel="noreferrer">ottctv@branch.com</a> with any questions.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>You can use telnet to view your Roku device logs: <code>telnet ROKU_LOCAL_IP 8085</code>, where <code>ROKU_LOCAL_IP</code> is your Roku&#39;s local IP address.</p></div>',7)])])}const _=o(i,[["render",r]]);export{h as __pageData,_ as default};
